import React, { useState, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import WelcomeScreen from './components/WelcomeScreen';
import ChatMessage from './components/ChatMessage';
import { streamChatResponse } from './services/geminiService';
import { Message, Role } from './types';
import { Icons } from './constants';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);

  // Ref for auto-scrolling
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const isWelcomeMode = messages.length === 0;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [inputText]);

  const handleSendMessage = async () => {
    if (!inputText.trim() || isStreaming) return;

    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: Role.USER,
      text: inputText.trim()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsStreaming(true);

    // Prepare model placeholder
    const modelMsgId = (Date.now() + 1).toString();
    const initialModelMessage: Message = {
      id: modelMsgId,
      role: Role.MODEL,
      text: '',
      isStreaming: true
    };
    setMessages(prev => [...prev, initialModelMessage]);

    try {
      // Create history for API
      const apiHistory = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      // Start streaming
      await streamChatResponse(
        userMessage.text, 
        apiHistory,
        (chunk) => {
          setMessages(prev => prev.map(msg => 
            msg.id === modelMsgId 
              ? { ...msg, text: msg.text + chunk } 
              : msg
          ));
        }
      );
    } catch (error) {
      setMessages(prev => prev.map(msg => 
        msg.id === modelMsgId 
          ? { ...msg, text: "Sorry, I encountered an error. Please check your API Key." } 
          : msg
      ));
    } finally {
      setIsStreaming(false);
      setMessages(prev => prev.map(msg => 
        msg.id === modelMsgId 
          ? { ...msg, isStreaming: false } 
          : msg
      ));
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleSuggestionClick = (text: string) => {
    setInputText(text);
    // Optional: auto-send
    // setTimeout(() => handleSendMessage(), 100); 
  };

  const startNewChat = () => {
    setMessages([]);
    setInputText('');
    setIsStreaming(false);
  };

  return (
    <div className="flex h-screen w-full bg-white overflow-hidden font-sans">
      <Sidebar onNewChat={startNewChat} />

      <main className="flex-1 flex flex-col relative">
        {/* Messages Area */}
        <div className={`flex-1 overflow-y-auto px-4 ${isWelcomeMode ? 'flex flex-col' : 'pt-6'}`}>
          {isWelcomeMode ? (
            <WelcomeScreen onSuggestionClick={handleSuggestionClick} />
          ) : (
            <div className="max-w-3xl mx-auto w-full pb-32">
              {messages.map(msg => (
                <ChatMessage key={msg.id} message={msg} />
              ))}
              <div ref={messagesEndRef} />
            </div>
          )}
        </div>

        {/* Input Area - Positioned conditionally or sticky at bottom */}
        <div className={`
          transition-all duration-500 ease-in-out
          ${isWelcomeMode 
            ? 'absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-[20px] w-full max-w-3xl px-4' 
            : 'absolute bottom-0 left-0 w-full bg-white/90 backdrop-blur-sm border-t border-gray-100 p-4'
          }
        `}>
          <div className={`
            mx-auto w-full
            ${isWelcomeMode ? '' : 'max-w-3xl'}
            bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden
            flex flex-col
          `}>
            {/* Text Input */}
            <textarea
              ref={textareaRef}
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="发送消息或输入 @ 选择技能"
              className="w-full max-h-40 p-4 text-gray-700 placeholder-gray-400 focus:outline-none resize-none bg-transparent custom-scrollbar"
              rows={isWelcomeMode ? 3 : 1}
            />

            {/* Toolbar */}
            <div className="flex items-center justify-between px-3 py-2 bg-gray-50/50 border-t border-gray-50">
              <div className="flex space-x-2">
                <button className="flex items-center space-x-1 px-3 py-1.5 rounded-lg bg-white border border-gray-200 text-xs text-gray-600 hover:bg-gray-50 hover:text-blue-600 transition-colors shadow-sm">
                  <Icons.Sparkles />
                  <span>知识库提问</span>
                </button>
                <button className="flex items-center space-x-1 px-3 py-1.5 rounded-lg bg-white border border-gray-200 text-xs text-gray-600 hover:bg-gray-50 hover:text-blue-600 transition-colors shadow-sm">
                   {/* Simplified icon for knowledge graph */}
                   <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="3"/><path d="M12 9V3"/><path d="M12 21v-6"/><path d="M9 12H3"/><path d="M21 12h-6"/></svg>
                  <span>知识图谱</span>
                </button>
              </div>

              <button 
                onClick={handleSendMessage}
                disabled={!inputText.trim() || isStreaming}
                className={`
                  p-2 rounded-full transition-all duration-200
                  ${inputText.trim() 
                    ? 'bg-blue-600 text-white shadow-md hover:bg-blue-700 transform hover:scale-105' 
                    : 'bg-gray-200 text-gray-400 cursor-not-allowed'}
                `}
              >
                {isStreaming ? (
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                ) : (
                  <Icons.Send />
                )}
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

