import React, { useState, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import WelcomeScreen from './components/WelcomeScreen';
import ChatMessage from './components/ChatMessage';
import { streamChatResponse } from './services/geminiService';
import { Message, Role } from './types';
import { Icons, INPUT_CHIPS } from './constants';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);

  // Ref for auto-scrolling
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const isWelcomeMode = messages.length === 0;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [inputText]);

  const handleSendMessage = async () => {
    if (!inputText.trim() || isStreaming) return;

    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: Role.USER,
      text: inputText.trim()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsStreaming(true);

    // Prepare model placeholder
    const modelMsgId = (Date.now() + 1).toString();
    const initialModelMessage: Message = {
      id: modelMsgId,
      role: Role.MODEL,
      text: '',
      isStreaming: true
    };
    setMessages(prev => [...prev, initialModelMessage]);

    try {
      // Create history for API
      const apiHistory = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      // Start streaming
      await streamChatResponse(
        userMessage.text, 
        apiHistory,
        (chunk) => {
          setMessages(prev => prev.map(msg => 
            msg.id === modelMsgId 
              ? { ...msg, text: msg.text + chunk } 
              : msg
          ));
        }
      );
    } catch (error) {
      setMessages(prev => prev.map(msg => 
        msg.id === modelMsgId 
          ? { ...msg, text: "Sorry, I encountered an error. Please check your API Key." } 
          : msg
      ));
    } finally {
      setIsStreaming(false);
      setMessages(prev => prev.map(msg => 
        msg.id === modelMsgId 
          ? { ...msg, isStreaming: false } 
          : msg
      ));
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleSuggestionClick = (text: string) => {
    setInputText(text);
  };

  const startNewChat = () => {
    setMessages([]);
    setInputText('');
    setIsStreaming(false);
  };

  return (
    <div className="flex h-screen w-full bg-gray-50 overflow-hidden font-sans">
      <Sidebar onNewChat={startNewChat} />

      <main className="flex-1 flex flex-col relative bg-white rounded-l-3xl shadow-2xl my-2 mr-2 border border-gray-100 overflow-hidden">
        {/* Messages Area */}
        <div className={`flex-1 overflow-y-auto px-4 ${isWelcomeMode ? 'flex flex-col' : 'pt-6'}`}>
          {isWelcomeMode ? (
            <WelcomeScreen onSuggestionClick={handleSuggestionClick} />
          ) : (
            <div className="max-w-3xl mx-auto w-full pb-32">
              {messages.map(msg => (
                <ChatMessage key={msg.id} message={msg} />
              ))}
              <div ref={messagesEndRef} />
            </div>
          )}
        </div>

        {/* Input Area */}
        <div className={`
          transition-all duration-500 ease-in-out z-20
          ${isWelcomeMode 
            ? 'absolute top-[48%] left-1/2 transform -translate-x-1/2 w-full max-w-3xl px-8' 
            : 'absolute bottom-0 left-0 w-full bg-white/95 backdrop-blur-md border-t border-gray-100 p-6'
          }
        `}>
          <div className={`
            w-full transition-all duration-300
            ${isWelcomeMode 
               ? 'bg-white shadow-[0_8px_30px_rgb(0,0,0,0.08)] border border-gray-200 rounded-2xl p-2' 
               : 'bg-gray-50 border border-gray-200 rounded-2xl p-1 max-w-3xl mx-auto'
            }
          `}>

            {/* Input Textarea */}
            <div className="relative">
               <textarea
                  ref={textareaRef}
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder="输入您的问题，或者选择下方技能..."
                  className={`
                     w-full focus:outline-none resize-none bg-transparent custom-scrollbar placeholder-gray-400 text-gray-700
                     ${isWelcomeMode ? 'p-4 min-h-[60px] text-base' : 'p-3 max-h-32 text-sm'}
                  `}
                  rows={1}
               />

               {/* Right side icons in Welcome Mode */}
               {isWelcomeMode && (
                  <div className="absolute right-3 top-3 flex items-center space-x-2 text-gray-400">
                     <button className="p-2 hover:bg-gray-100 rounded-full transition-colors"><Icons.Mic /></button>
                     <button 
                        onClick={handleSendMessage}
                        disabled={!inputText.trim()}
                        className={`p-2 rounded-full transition-colors ${inputText.trim() ? 'text-blue-600 bg-blue-50' : 'hover:bg-gray-100'}`}
                     >
                        <Icons.Send />
                     </button>
                  </div>
               )}
            </div>

            {/* Bottom Toolbar Area */}
            <div className={`flex items-center justify-between ${isWelcomeMode ? 'px-4 pb-2 mt-2' : 'px-2 pb-1'}`}>

               {/* Left: Chips or Tools */}
               <div className="flex items-center flex-wrap gap-2">
                  {isWelcomeMode ? (
                     // Welcome Mode: Suggestion Chips
                     INPUT_CHIPS.map(chip => (
                        <button 
                           key={chip}
                           onClick={() => handleSuggestionClick(chip)}
                           className="px-3 py-1.5 bg-gray-50 hover:bg-gray-100 text-gray-500 text-xs rounded-md border border-transparent hover:border-gray-200 transition-all"
                        >
                           {chip}
                        </button>
                     ))
                  ) : (
                     // Chat Mode: Tools
                     <div className="flex space-x-1">
                        <button className="p-2 text-gray-400 hover:text-blue-600 hover:bg-white rounded-lg transition-colors"><Icons.Sparkles /></button>
                        <button className="p-2 text-gray-400 hover:text-blue-600 hover:bg-white rounded-lg transition-colors"><Icons.Layout /></button>
                     </div>
                  )}
               </div>

               {/* Right: Send Button (Only in Chat Mode here, it's absolute in Welcome Mode) */}
               {!isWelcomeMode && (
                  <button 
                  onClick={handleSendMessage}
                  disabled={!inputText.trim() || isStreaming}
                  className={`
                     p-2 rounded-xl transition-all duration-200
                     ${inputText.trim() 
                        ? 'bg-blue-600 text-white shadow-md hover:bg-blue-700' 
                        : 'bg-transparent text-gray-300'}
                  `}
                  >
                  {isStreaming ? (
                     <div className="w-5 h-5 border-2 border-current border-t-transparent rounded-full animate-spin" />
                  ) : (
                     <Icons.Send />
                  )}
                  </button>
               )}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

