              <div key={item.id} className="group flex items-center px-3 py-2 hover:bg-gray-100 rounded-lg cursor-pointer transition-colors text-gray-600 mb-0.5 relative">
                <span className="text-blue-500 mr-2.5 transform scale-90"><Icons.Pin /></span>
                <span className="truncate flex-1 text-sm pr-6">{item.title}</span>
                {/* Unpin Action */}
                <button
                    onClick={(e) => { e.stopPropagation(); onTogglePin(item.id); }}
                    className="absolute right-2 opacity-0 group-hover:opacity-100 p-1 hover:bg-gray-200 rounded transition-all text-gray-400 hover:text-gray-600"
                    title="取消置顶"
                >
                    <Icons.PinOff />
                </button>
              </div>
            ))}

            {/* Recent Items */}
            {recentHistory.map(item => (
              <div key={item.id} className="group flex items-center px-3 py-2 hover:bg-gray-100 rounded-lg cursor-pointer transition-colors text-gray-600 mb-0.5 relative">
                <span className="text-gray-300 mr-2.5 transform scale-90 group-hover:text-gray-400"><Icons.Clock /></span>
                <span className="truncate flex-1 text-sm pr-6">{item.title}</span>
                {/* Pin Action */}
                <button
                    onClick={(e) => { e.stopPropagation(); onTogglePin(item.id); }}
                    className="absolute right-2 opacity-0 group-hover:opacity-100 p-1 hover:bg-gray-200 rounded transition-all text-gray-400 hover:text-gray-600"
                    title="置顶"
                >
                    <Icons.Pin />
                </button>
              </div>
            ))}
          </div>
        )}

        {/* Common Apps Section */}
        <div className="mt-2 mb-4 pt-4 border-t border-gray-100">
          <div className="px-3 py-1 text-xs text-gray-400 font-medium mb-2">常用应用</div>
          {COMMON_APPS.map(app => (
            <div key={app.id} className="flex items-center px-3 py-2 hover:bg-gray-100 rounded-lg cursor-pointer transition-colors mb-1">
              <div className={`w-6 h-6 rounded-md flex items-center justify-center text-sm mr-3 ${app.color}`}>
                {app.icon}
              </div>
              <span className="truncate flex-1 text-gray-700 text-sm">{app.name}</span>
            </div>
          ))}
        </div>
      </div>

      {/* User Footer - Simplified */}
      <div className="p-4 border-t border-gray-100">
        <div className="flex items-center space-x-3 cursor-pointer hover:bg-gray-50 p-2 rounded-xl transition-colors">
          <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center text-xs font-bold border border-blue-200">
             U
          </div>
          <div className="flex-1 min-w-0">
             <p className="text-sm font-medium text-gray-700 truncate">Admin User</p>
          </div>
          <div className="text-gray-400">
             <Icons.MoreHorizontal />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;
